import { useState } from 'react';

const tabs = [
  { name: 'Profile', content: 'Profile Content' },
  { name: 'Account', content: 'Account Content' },
  { name: 'Notifications', content: 'Notifications Content' },
  { name: 'Security', content: 'Security Content' },
  { name: 'Billing', content: 'Billing Content' },
];

export default function SettingsPage() {
  const [activeTab, setActiveTab] = useState(tabs[0].name);

  return (
    <div className="flex">
      {/* Vertical Tab Navigation */}
      <nav className="w-1/4 border-r border-gray-300">
        <ul className="flex flex-col">
          {tabs.map((tab) => (
            <li key={tab.name}>
              <button
                className={`w-full text-left p-4 ${
                  activeTab === tab.name ? 'bg-gray-200 font-bold' : 'hover:bg-gray-100'
                }`}
                onClick={() => setActiveTab(tab.name)}
              >
                {tab.name}
              </button>
            </li>
          ))}
        </ul>
      </nav>

      {/* Content Panel */}
      <div className="w-3/4 p-4">
        {tabs.find((tab) => tab.name === activeTab)?.content}
      </div>
    </div>
  );
}
